mapper.select:
SELECT t.* FROM(
SELECT id ,accid,user_id userId,deduction,source,create_time createTime,update_time updateTime,CONCAT(1)type,CONCAT('') address,CONCAT('') thumbnailUrl from app_push_bill  WHERE user_id = #{id}

    union ALL

SELECT a.id,a.id accid,user_b_id userId,CONCAT('')deduction,CONCAT('')source , a.create_time createTime,a.update_time updateTime,CONCAT(2)type,adress address,b.url thumbnailUrl FROM app_send_out_sheet as a
    LEFT JOIN app_send_url as b ON a.id = b.send_id
 WHERE  b.`index` = 1  AND user_b_id = #{id}
)as t ORDER BY createTime DESC LIMIT #{pagesize},20

 SELECT t.* FROM(
SELECT id ,accid,user_id userId,deduction,source,create_time createTime,update_time updateTime,CONCAT(1)type,CONCAT('') address,CONCAT('') thumbnailUrl,track_state trackState from app_push_bill  WHERE user_id = #{id}

    union ALL

SELECT a.id,a.id accid,user_b_id userId,CONCAT('')deduction,CONCAT('')source , a.create_time createTime,a.update_time updateTime,CONCAT(2)type,adress address,b.url thumbnailUrl,track_state trackState FROM app_send_out_sheet as a
    LEFT JOIN app_send_url as b ON a.id = b.send_id
 WHERE  b.`index` = 1  AND user_b_id = #{id}
)as t
    	WHERE t.address LIKE "%"#{text,jdbcType=VARCHAR}"%"
 ORDER BY createTime DESC LIMIT #{pagesize},20

SELECT  count(1) allbill,COALESCE(SUM(momey),0) allIndent   FROM app_user_account_record
        WHERE user_id = #{id} AND type = 20  AND  add_flag = 2 AND  source =1
         AND year(create_time) = #{year} AND month(create_time) = #{year}
